SELECT , g.goods_name AS goodsName, c.cust_name AS custName, AS userName FROM sale_order s LEFT JOIN goods g ON s.goods_id = g.id LEFT JOIN customer c ON s.cust_id = c.id LEFT JOIN user u ON s.user_id = u.id
and s.status = #{status}
ORDER BY s.sale_time DESC

SELECT
    ,
    g.goods_name  AS goodsName,
    c.cust_name AS custName,
     AS userName
    FROM sale_order s
    LEFT JOIN goods g ON s.goods_id = g.id
    LEFT JOIN customer c ON s.cust_id = c.id
    LEFT JOIN user u ON s.user_id = u.id


            and s.status = #{status}


            and s.goods_id = #{goodsId}


            and s.cust_id = #{custId}


            and s.sale_time between #{saleTimeStart} and #{saleTimeEnd}


            and s.user_id = #{userId}


    order by s.sale_time DESC
